// Valida inputs y normaliza canales.
const d = $json;

if (!d.session_id || typeof d.session_id !== 'string') {
  throw new Error('session_id requerido');
}
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(d.session_id)) {
  throw new Error('session_id debe ser UUID valido');
}

// Normaliza canales: acepta array o string 'ambos'
let canales = [];
if (Array.isArray(d.canales)) {
  canales = d.canales.map(c => String(c).toLowerCase().trim());
} else if (typeof d.canales === 'string') {
  const raw = d.canales.toLowerCase().trim();
  if (raw === 'ambos' || raw === 'both') canales = ['email', 'whatsapp'];
  else canales = [raw];
}
canales = canales.filter(c => ['email', 'whatsapp'].includes(c));
if (canales.length === 0) canales = ['email']; // fallback

const parcelas = Array.isArray(d.parcelas_recomendadas)
  ? d.parcelas_recomendadas.map(p => String(p).toUpperCase().trim()).filter(Boolean)
  : [];

return [{ json: {
  session_id: d.session_id,
  canales,
  parcelas_recomendadas: parcelas,
  forma_pago: (d.forma_pago || '').toString().toLowerCase().trim(),
  presupuesto_o_pie_clp: Number(d.presupuesto_o_pie_clp) || 0,
  uso: (d.uso || '').toString().toLowerCase().trim(),
  resumen_conversacion: (d.resumen_conversacion || '').toString().slice(0, 1200),
  send_email: canales.includes('email'),
  send_whatsapp: canales.includes('whatsapp'),
} }];

// Construye HTML del email + texto de WhatsApp con las parcelas recomendadas.
const input = $('Validate Input').first().json;
const leadArr = $('Fetch Lead').first().json;
const sheetItem = $('Fetch Sheet').first().json;
const uf = $json;

const ufValor = uf && uf.serie && uf.serie[0] && typeof uf.serie[0].valor === 'number' ? uf.serie[0].valor : null;

if (!Array.isArray(leadArr) || leadArr.length === 0) {
  return [{ json: {
    ok: false,
    skip: true,
    tool_output_text: 'No encontre tu registro de sesion para enviar el resumen. Confirma tu nombre, email y WhatsApp para continuar.',
  } }];
}
const lead = leadArr[0];
const primerNombre = (lead.nombre || '').split(' ')[0] || 'Cliente';

// Parse CSV inventario
const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
function parseCsv(text) {
  const rows = [];
  let row = []; let field = ''; let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else inQuotes = !inQuotes;
    } else if (c === ',' && !inQuotes) { row.push(field); field = ''; }
    else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else field += c;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}
const pm = (s) => { if (!s) return null; const t = s.toString(); if (t.includes('#')) return null; const n = t.replace(/[^0-9]/g, ''); return n ? parseInt(n, 10) : null; };
const ps = (s) => { if (!s) return null; const n = s.toString().replace(/[^0-9]/g, ''); return n ? parseInt(n, 10) : null; };
const normEstado = (r) => { const e = (r || '').toString().trim().toLowerCase(); if (e.startsWith('disponi')) return 'disponible'; if (e.startsWith('reserv')) return 'reservado'; if (e.startsWith('vendi')) return 'vendido'; return e; };

const rows = parseCsv(csvText);
const byNumero = new Map();
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  const cuotaClp = pm(r[11]);
  byNumero.set(lote.toUpperCase(), {
    numero: lote.toUpperCase(),
    destacada: ((r[0] || '').toString().trim() === '⭐'),
    estado: normEstado(r[2]),
    tamano_m2: ps(r[3]),
    precio_contado: pm(r[6]),
    descuento_pct: ps(r[7]),
    precio_credito: pm(r[9]),
    pie_minimo_50pct: pm(r[10]),
    cuota_mensual_clp: cuotaClp,
    cuota_mensual_uf: cuotaClp && ufValor ? Math.round((cuotaClp / ufValor) * 100) / 100 : null,
  });
}

const parcelas = input.parcelas_recomendadas
  .map(n => byNumero.get(n.toUpperCase()))
  .filter(Boolean);

const fmtClp = (n) => n === null || n === undefined ? '—' : `$${n.toLocaleString('es-CL')}`;
const fmtUf = (n) => n === null || n === undefined ? '—' : `${n.toFixed(2)} UF`;

const BASE_URL = 'https://mirador-villarrica-chatbot-pruebasn8ncub-6852s-projects.vercel.app';
const LOGO_MIRADOR = `${BASE_URL}/assets/mirador-logo.png`;
const LOGO_TERRA = `${BASE_URL}/assets/terra-segura-logo.png`;

const SHEET_URL = 'https://docs.google.com/spreadsheets/d/1gtqd1Xb6Yr3g3myw0nnJDsnZUSybQYS9aFAEJWaPqhQ/edit?gid=1975618999';
const TOUR_URL = 'https://lanube360.com/mirador-de-villarrica/';
const LOCATION_URL = 'https://www.google.com/maps/place/39%C2%B000%2752.4%22S+72%C2%B007%2740.8%22W/';
const WA_COMERCIAL = '+56 9 4032 9987';
const WA_LINK = 'https://wa.me/56940329987';

// ---------- HTML email ----------
const parcelasHtml = parcelas.length === 0
  ? '<p style="margin:0;color:#666;font-size:14px;">El equipo le enviará recomendaciones en detalle pronto.</p>'
  : parcelas.map(p => {
      const disp = p.estado === 'disponible' ? '✅ Disponible' : p.estado === 'reservado' ? '⏳ Reservada' : '❌ Vendida';
      const pagoLabel = input.forma_pago === 'credito' ? 'Crédito directo' : 'Contado';
      const pagoValue = input.forma_pago === 'credito'
        ? `Pie 50% ${fmtClp(p.pie_minimo_50pct)} + 36 cuotas de ${fmtUf(p.cuota_mensual_uf)} (~${fmtClp(p.cuota_mensual_clp)} al UF hoy)`
        : `${fmtClp(p.precio_contado)} (dcto ${p.descuento_pct || 0}%)`;
      return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;border:1px solid #d7dcd5;border-radius:8px;margin:14px 0;overflow:hidden;">`
        + `<tr><td style="background:#1a3d2e;padding:12px 18px;">`
        + `<span style="color:#fff;font-size:16px;font-weight:bold;">Parcela ${p.numero}${p.destacada ? ' ⭐' : ''}</span>`
        + `</td></tr>`
        + `<tr><td style="padding:14px 18px;background:#fff;">`
        + `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="font-size:14px;color:#333;">`
        + `<tr><td style="padding:6px 0;width:40%;color:#666;">Tamaño</td><td style="padding:6px 0;font-weight:bold;">${p.tamano_m2 || '—'} m²</td></tr>`
        + `<tr><td style="padding:6px 0;color:#666;">Estado</td><td style="padding:6px 0;font-weight:bold;">${disp}</td></tr>`
        + `<tr><td style="padding:6px 0;color:#666;">${pagoLabel}</td><td style="padding:6px 0;font-weight:bold;">${pagoValue}</td></tr>`
        + `</table>`
        + `</td></tr></table>`;
    }).join('');

const usoLabel = input.uso === 'inversion' ? 'inversión' : input.uso === 'segunda' ? 'segunda vivienda' : input.uso === 'vivienda' ? 'vivienda permanente' : '';
const pagoIntro = input.forma_pago === 'credito' ? ' con financiamiento vía crédito directo' : input.forma_pago === 'contado' ? ' con pago contado' : '';
const safeResumen = (input.resumen_conversacion || '').replace(/</g, '&lt;');

const emailHtml = ''
  + '<div style="margin:0;padding:0;background:#f1ede4;">'
  + '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f1ede4;padding:20px 0;">'
  + '<tr><td align="center">'
  + '<table role="presentation" width="640" cellpadding="0" cellspacing="0" style="max-width:640px;background:#ffffff;border-radius:10px;overflow:hidden;font-family:Arial,Helvetica,sans-serif;color:#333;">'
  // HEADER VERDE con logo Mirador + Terra Segura
  + '<tr><td style="background:#1a3d2e;padding:36px 20px 28px;text-align:center;">'
  + `<img src="${LOGO_MIRADOR}" width="220" alt="Mirador de Villarrica" style="display:block;max-width:220px;height:auto;margin:0 auto 22px;border:0;"/>`
  + '<table role="presentation" align="center" cellpadding="0" cellspacing="0"><tr>'
  + '<td style="padding:0 10px 0 0;color:#f4a84b;font-size:11px;letter-spacing:2px;text-transform:uppercase;font-family:Arial,sans-serif;">Un proyecto de</td>'
  + `<td><img src="${LOGO_TERRA}" width="140" alt="Terra Segura" style="display:block;max-width:140px;height:auto;border:0;"/></td>`
  + '</tr></table>'
  + '</td></tr>'
  // SALUDO
  + '<tr><td style="padding:32px 32px 8px;">'
  + `<h1 style="color:#1a3d2e;margin:0 0 16px;font-size:22px;font-weight:bold;">Su recomendación personalizada</h1>`
  + `<p style="margin:0 0 14px;font-size:15px;line-height:1.6;color:#333;">Estimado/a <strong>${primerNombre}</strong>,</p>`
  + `<p style="margin:0 0 16px;font-size:15px;line-height:1.6;color:#333;">Gracias por conversar con nosotros. En base a su interés${usoLabel ? ' para <strong>' + usoLabel + '</strong>' : ''}${pagoIntro}, preparamos este resumen con las parcelas que mejor se ajustan a su perfil.</p>`
  + '</td></tr>'
  // RESUMEN DEL CASO
  + (safeResumen ? `<tr><td style="padding:0 32px;"><div style="background:#f9f6f0;border-left:4px solid #f4a84b;padding:16px 20px;border-radius:4px;"><p style="margin:0 0 6px;font-size:11px;color:#8a6a2e;text-transform:uppercase;letter-spacing:1.5px;font-weight:bold;">Resumen de su caso</p><p style="margin:0;font-size:14px;line-height:1.6;color:#444;">${safeResumen}</p></div></td></tr>` : '')
  // PARCELAS
  + '<tr><td style="padding:24px 32px 8px;">'
  + '<h2 style="color:#1a3d2e;font-size:18px;margin:0 0 4px;font-weight:bold;">Parcelas recomendadas</h2>'
  + parcelasHtml
  + '</td></tr>'
  // RECURSOS — botones
  + '<tr><td style="padding:12px 32px 24px;">'
  + '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f9f6f0;border-radius:8px;padding:0;">'
  + '<tr><td style="padding:24px 20px 8px;text-align:center;">'
  + '<p style="margin:0 0 4px;color:#1a3d2e;font-size:17px;font-weight:bold;">Recursos del proyecto</p>'
  + '<p style="margin:0 0 20px;color:#666;font-size:13px;">Explore el proyecto a su ritmo</p>'
  + '</td></tr>'
  + '<tr><td align="center" style="padding:0 20px 20px;">'
  + '<table role="presentation" cellpadding="0" cellspacing="0" style="margin:0 auto;">'
  + `<tr><td style="padding:5px;"><a href="${TOUR_URL}" style="display:inline-block;background:#1a3d2e;color:#ffffff;padding:14px 28px;text-decoration:none;border-radius:6px;font-size:14px;font-weight:bold;min-width:220px;text-align:center;">🎥 Recorrer tour 360°</a></td></tr>`
  + `<tr><td style="padding:5px;"><a href="${SHEET_URL}" style="display:inline-block;background:#f4a84b;color:#1a3d2e;padding:14px 28px;text-decoration:none;border-radius:6px;font-size:14px;font-weight:bold;min-width:220px;text-align:center;">📋 Ver inventario en vivo</a></td></tr>`
  + `<tr><td style="padding:5px;"><a href="${LOCATION_URL}" style="display:inline-block;background:#ffffff;color:#1a3d2e;border:2px solid #1a3d2e;padding:12px 28px;text-decoration:none;border-radius:6px;font-size:14px;font-weight:bold;min-width:218px;text-align:center;">📍 Ver ubicación en mapa</a></td></tr>`
  + '</table>'
  + '</td></tr>'
  + '</table>'
  + '</td></tr>'
  // CTA CONTACTO
  + '<tr><td style="background:#1a3d2e;padding:26px 20px;text-align:center;">'
  + '<p style="color:#ffffff;margin:0 0 14px;font-size:15px;font-weight:bold;">¿Listo para avanzar?</p>'
  + `<a href="${WA_LINK}" style="display:inline-block;background:#25D366;color:#ffffff;padding:13px 26px;text-decoration:none;border-radius:6px;font-weight:bold;font-size:14px;">💬 Escribir por WhatsApp</a>`
  + `<p style="color:#c5d5cc;margin:14px 0 0;font-size:12px;">O responda este correo · ${WA_COMERCIAL}</p>`
  + '</td></tr>'
  // FOOTER
  + '<tr><td style="background:#122a20;padding:18px 20px;text-align:center;">'
  + '<p style="color:#8ea89b;margin:0;font-size:11px;line-height:1.6;">Equipo de Ventas — Terra Segura Inmobiliaria<br/>Mirador de Villarrica · IX Región</p>'
  + '</td></tr>'
  + '</table>'
  + '</td></tr>'
  + '</table>'
  + '</div>';

// ---------- WhatsApp text ----------
const waLines = [
  `*Mirador de Villarrica — Recomendación personalizada*`,
  ``,
  `Hola ${primerNombre}, dejamos por escrito las parcelas que revisamos:`,
];
if (parcelas.length === 0) {
  waLines.push('', '_El equipo le enviará recomendaciones en detalle pronto._');
} else {
  parcelas.forEach(p => {
    const dest = p.destacada ? ' ⭐' : '';
    waLines.push('');
    waLines.push(`• *Parcela ${p.numero}*${dest} · ${p.tamano_m2} m² · _${p.estado}_`);
    if (input.forma_pago === 'credito') {
      waLines.push(`  Pie 50%: ${fmtClp(p.pie_minimo_50pct)}`);
      waLines.push(`  36 cuotas: ${fmtUf(p.cuota_mensual_uf)} (~${fmtClp(p.cuota_mensual_clp)} al UF hoy)`);
    } else {
      waLines.push(`  Contado: ${fmtClp(p.precio_contado)} (dcto ${p.descuento_pct || 0}%)`);
    }
  });
}
waLines.push('');
waLines.push(`📋 Inventario completo: ${SHEET_URL}`);
waLines.push(`🎥 Tour 360°: ${TOUR_URL}`);
waLines.push(`📍 Ubicación: ${LOCATION_URL}`);
waLines.push('');
waLines.push(`Si quiere avanzar, escríbanos al ${WA_COMERCIAL} o responda aquí mismo.`);

const whatsappText = waLines.join('\n');

// Normaliza numero de WhatsApp del lead
let phoneClean = '';
if (lead.whatsapp) {
  phoneClean = lead.whatsapp.replace(/[^0-9]/g, '');
  if (phoneClean.startsWith('9') && phoneClean.length === 9) phoneClean = '56' + phoneClean;
}

const canValidEmail = input.send_email && lead.email && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(lead.email);
const canValidWa = input.send_whatsapp && phoneClean.length >= 10;

return [{ json: {
  ok: true,
  skip: false,
  session_id: input.session_id,
  lead_id: lead.id,
  nombre: lead.nombre,
  primerNombre,
  email: lead.email,
  phone_clean: phoneClean,
  can_email: canValidEmail,
  can_whatsapp: canValidWa,
  emailHtml,
  whatsappText,
  parcelas_ok: parcelas.length,
  canales_input: input.canales,
  score_history: Array.isArray(lead.score_history) ? lead.score_history : [],
} }];

// Merge resultados de ambos canales (si corresponde), PATCH Supabase, arma tool_output_text.
const built = $('Build Messages').first().json;

const SUPABASE_URL = 'https://segllewycyscyenvqtes.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InNlZ2xsZXd5Y3lzY3llbnZxdGVzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NjI1NDg1MCwiZXhwIjoyMDkxODMwODUwfQ.NuKXzAXPeENkmjxRYpX_5faw5JOP32bvgZRL284dJHI';

const sent = [];
if (built.can_email) sent.push('email');
if (built.can_whatsapp) sent.push('whatsapp');

const history = built.score_history.slice();
history.push({
  at: new Date().toISOString(),
  action: 'resumen_enviado',
  canales: sent,
});

const patchBody = {
  canales_envio: sent,
  resumen_enviado_at: new Date().toISOString(),
  score_history: history,
};

const res = await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/leads?session_id=eq.${built.session_id}`,
  headers: {
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal',
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`,
  },
  body: patchBody,
  json: true,
  returnFullResponse: false,
});

const canalesTexto = sent.length === 2 ? 'por correo y WhatsApp' : sent[0] === 'email' ? 'por correo' : sent[0] === 'whatsapp' ? 'por WhatsApp' : 'por el canal disponible';

return [{ json: {
  ok: true,
  lead_id: built.lead_id,
  canales_enviados: sent,
  tool_output_text: sent.length > 0
    ? `Listo ${built.primerNombre}, le enviamos el resumen con las parcelas que conversamos ${canalesTexto}. Revíselo con calma y cualquier duda me la cuenta por acá.`
    : `No pude enviar el resumen porque no tengo ${built.can_email ? '' : 'correo válido'}${!built.can_email && !built.can_whatsapp ? ' ni ' : ''}${built.can_whatsapp ? '' : 'WhatsApp válido'}. ¿Me los confirma para intentar de nuevo?`,
} }];
